function cleanPrompt(raw) {
  let p = raw ?? '';
  if (Array.isArray(p)) p = p.join(' ');
  if (typeof p !== 'string') p = String(p);
  p = p.replace(/\r?\n+/g, ' ').replace(/\s{2,}/g, ' ').trim();
  const negIdx = p.indexOf('Negative prompt:');
  if (negIdx >= 0) p = p.slice(0, negIdx).trim();
  return p;
}

function normAspect(v) {
  const s = String(v ?? '').trim().toLowerCase();
  if (!s) return '9:16';
  if (s === 'portrait') return '9:16';
  if (s === 'landscape') return '16:9';
  if (s === '9:16' || s === '9/16') return '9:16';
  if (s === '16:9' || s === '16/9') return '16:9';
  return '9:16';
}

function normalizeModel(v) {
  const s = String(v ?? '').trim().toLowerCase();
  const map = {
    sora2: 'sora-2-all',
    'sora-2': 'sora-2-all',
    'sora-2-all': 'sora-2-all',
    'sora-2-text-to-video': 'sora-2-text-to-video'
  };
  return map[s] || 'sora-2-all';
}

function toOrientation(val) {
  return val === '16:9' ? 'landscape' : 'portrait';
}

function toDuration(payload) {
  const d = Number(payload.n_frames ?? payload.duration ?? 15);
  return Number.isFinite(d) && d > 0 ? d : 15;
}

const payload = $('子流程入口-sora').first().json.body || {};
const replication_id = String(payload.replication_id || '').trim();
const callback_url = String(payload.callback_url || '').trim();
const api_key = String(payload.api_key || '').trim();
const workflow_id_for_credits = String(payload.workflow_id_for_credits || '').trim();

if (!replication_id || !api_key) {
  throw new Error('缺少必要字段（replication_id / api_key）');
}

const prompt = cleanPrompt(payload.prompt);
if (!prompt) throw new Error('prompt 为空');

const model = normalizeModel(payload.model);
const aspect_ratio = normAspect(payload.aspect_ratio);
const orientation = toOrientation(aspect_ratio);
const duration = toDuration(payload);

const itemJson = $input.first().json || {};
const imageUrl = itemJson.imageUrl || '';
const images = imageUrl ? [imageUrl] : [];

const requestBody = {
  model,
  prompt,
  images,
  orientation,
  size: 'large',
  duration,
  watermark: false
};

return [{
  json: {
    requestBody,
    replication_id,
    callback_url,
    api_key,
    workflow_id_for_credits,
    debug: { model, aspect_ratio, orientation, duration, has_image: !!imageUrl }
  }
}];

const res = $input.first().json || {};

const id = res.id || res.data?.id;
const status = res.status || res.data?.status || 'unknown';

if (!id) {
  throw new Error(`创建任务失败，响应里没有 id：${JSON.stringify(res).slice(0, 500)}`);
}

const ctx = $('清洗提示词').item.json || {};
return [{
  json: {
    id: ctx.replication_id,
    task_id: id,
    yunwu_status: status,
    replication_id: ctx.replication_id,
    callback_url: ctx.callback_url,
    api_key: ctx.api_key,
    workflow_id_for_credits: ctx.workflow_id_for_credits,
    startTime: Date.now()
  }
}];

const payload = $('子流程入口-sora').first().json.body || {};
const ctx = $('提取任务id').item.json || {};
const wid = String(payload.workflow_id_for_credits || '').trim();
const manualCallback = String(payload.callback_url || '').trim();

// For web: flowonn always calls our n8n sora_web_callback webhook,
// which handles FFmpeg + OSS + Supabase, then notifies the app via callback_url
if (manualCallback) {
  return [{
    json: {
      ...ctx,
      webhook_url: 'https://hooks.atomx.top/webhook/sora_web_callback',
      callback_url: manualCallback,
      workflow_id_for_credits: wid,
      callback_source: 'web'
    }
  }];
}

// Legacy Feishu fallback
const map = {
  flow_farm_md: 'https://hooks.flowonn.com/webhook/sora_md_callbackV4',
  flow_farm_zy: 'https://hooks.flowonn.com/webhook/sora_zy_callbackV4',
  flow_farm_copy: 'https://hooks.flowonn.com/webhook/sora_copy_callbackV4'
};

const webhook_url = map[wid] || 'https://hooks.flowonn.com/webhook/sora_zy_callbackV4';

return [{
  json: {
    ...ctx,
    webhook_url,
    workflow_id_for_credits: wid,
    callback_source: map[wid] ? 'workflow_map' : 'default'
  }
}];
